tokens WorkWithPlus (base-color:Blue,background-color:Light,menu-color:Dark)
{
	#borders  {
		xs: 1px;
		s: 2px;
	}
	//BORDER RADIUS
	#radius  {
		s: 2px;
		m: 4px;
		l: 6px;
	}
	//COLORS
	@base-color = Blue {
		#colors
		{
			#region BaseColors
				BaseColor: #078bcd;
				BaseColorForecolor: #078bcd;
				ActionBorder_and_FocusColor: #357ebd;
				ActionHover: #3276b1;
				ActionHoverBorder: #285e8e;
				BaseColorShadow: rgba(7, 139, 205, 0.7);
				BaseForecolor80: rgba(255,255,255,0.8);
				BaseColor30: rgba(7, 139, 205, 0.3);
				BaseForecolor: white;
			#endregion
		}
	}
	@background-color = Light {
		#colors
		{
			#region Grays
				gray01: #fbfbfb;
				gray02: #f7f7f7;
				gray03: #f5f4f4;
				gray04: #eee;
				gray05: #d9d9d9;
				gray06: #c8c8c8;
				gray07: #8c8d8e;
				gray08: #575b5d;
			#endregion
			#region Background_Colors
				BackgroundColor: white;
				DataBackgroundColor: #fff;
			#endregion
			#region Grid_Colors
				GridForecolor: #000;
				GridActionIconColor: #fff;
			#endregion
			GridTitleColor:#285e8e;
		}
	}
	@menu-color = Dark {
		#colors
		{
			SidebarMenu_BackgroundColor: #222D32;
			SidebarMenu_ItemHoverForecolor: #FFF;
			SidebarMenu_ItemOpenBackground: #1E282C;
			SidebarMenu_ItemForecolor: #B8C7CE;
			SidebarMenu_SelectedItemForecolor: #FFF;
			SidebarMenu_SubmenuItemForecolor: #889097;
			SidebarMenu_SubmenuItemHoverForecolor: #FFF;
			SidebarMenu_SelectedItemBackground: #1E282C;
			SidebarMenu_SubmenuSelectedItemBackground: #2C3B41;
			SidebarMenu_SubmenuSelectedItemForecolor: #FFF;
			SidebarMenu_LineSeparator: #222D32;
			SidebarMenu_ItemHoverBackground: #1E282C;
			SidebarMenu_LineSubmenuItemColor: #889097;
			SidebarMenu_CircleSubmenuItemColor: #889097;
			SidebarMenu_CircleSubmenuItemBackground: #E2E2E2;
			SidebarMenu_CircelSubmenuItemActiveColor: #5CB85C;
			SidebarMenu_BorderSecondLevelSubmenu: #889097;
			SidebarMenu_SubmenuItemBackground: #2C3B41;
			SidebarMenu_ScrollBackground: #222D32;
			SidebarMenu_HeaderBackground: #1A2226;
			SidebarMenu_SearchBackground: #374850;
			SidebarMenu_SearchBorderColor: #374850;
			SidebarMenu_SearchFocusBackground: #FFF;
			SidebarMenu_SubtitleBackground: #1A2226;
			SidebarMenu_SubtitleForecolor: #4B646F;
		}
	}
	#colors
	{
		HeaderForecolor: white;
		PDF: #ea4c3a;
		ExcelColor: #08743b;
		#region FormatAndAlerts
			Danger: #f56a67;
			Danger_CondForm: #dd4b39;
			Danger_CondForm_Row_Background: #f2dede;
			Danger_CondForm_Action: #e5cccc;
			Danger_CondForm_Action_Hover: rgba(245,106,103,0.5);
			Warning: #f39c12;
			Warning_CondForm: #fb6e52;
			Warning_CondForm_Row_Background: #faf2cc;
			Warning_CondForm_Action: #fed6be;
			Warning_CondForm_Action_Hover: rgba(251,110,82,0.5);
			Success_CondForm: #00a65a;
			Success_CondForm_Row_Background: #dff0d8;
			Success_CondForm_Action: #b9ccb7;
			Success_CondForm_Action_Hover: rgba(0,166,90,0.5);
			Info_CondForm: #3c8dbc;
			Info_CondForm_Row_Background: #e0f1ff;
			Info_CondForm_Action: #bcdcf5;
			Info_CondForm_Action_Hover: rgba(60,141,188,0.5);
			InfoLight: #00c0ef;
		#endregion
	}
	//TYPOGRAPHY -> Font
	#fonts  {
		primary-regular: Helvetica Neue, Helvetica, Arial, sans-serif;
	}
	//TYPOGRAPHY -> Font Sizes
	#fontSizes  {
		xs: 11px;
		s: 14px;
		m: 18px;
		l: 22px;
		xl: 28px;
		xxl: 34px;
		#region fontIconSizes
			font-icon-xxs: 10px;
			font-icon-xs: 12px;
			font-icon-s: 16px;
			font-icon-m: 19px;
			font-icon-l: 24px;
			font-icon-xl: 36px;
		#endregion
	}
}

styles WorkWithPlusBaseDS
{
	#region General
		BODY
		{
			height: 100%;
		}
		HTML
		{
			height: 100% !important;
		}
		HTML:not(.notChrome) input[type='checkbox']
		{
			margin-bottom: 0px;
			width: 0px;
			outline: 0;
		}
		HTML:not(.notChrome) input[type='checkbox'][disabled]:before
		{
			color:  $colors.gray06 !important;
		}
		HTML:not(.notChrome) input[type='checkbox']:before
		{
			font-family: "Font Awesome 5 Free";
			font-size: $fontSizes.font-icon-m;
			font-weight: normal;
			content:  "\f0c8";
			line-height: 0px;
		}
		HTML:not(.notChrome) input[type='checkbox']:checked:before
		{
			content:  "\f14a";
		}
		html:not(.notChrome) input:focus[type='checkbox']:before
		{
			color: $colors.BaseColor;
		}
		.MainContainer
		{
			padding-right: 15px;
			background-color: $colors.BackgroundColor;
		}
		.MainContainerWithFooter
		{
			@include MainContainer;
			height: 100%;
		}
		.MainContainerNoBackground
		{
			@include MainContainer;
			background-color: transparent;
		}
		.MainContainerBackgroundWhite
		{
			@include MainContainer;
			background-color: $colors.DataBackgroundColor;
		}
		html, body {
			margin: 0px;
			font-family: $fonts.primary-regular;
			font-size: $fontSizes.s;
			line-height: 1.42857143; //bootstrap-based value
			height: 100%;
		}
		.MainContainerWithFooter > .row
		{
			height: 100%;
		}
		.MainContainerWithFooter > .row > DIV
		{
			height: 100%;
			padding-left: 0;
		}
		.MainContainerWithFooter > .row:nth-child(2)
		{
			position: absolute;
			top: -10px;
			height: 0px;
		}
		.Form #gx-column-targets
		{
			display: table;
			width: 100%;
			height: 100vh;
			table-layout: fixed;
		}
		#gx-column-targets > DIV
		{
			height: 100%;
		}
	#endregion
	#region Main Tables
		.Table:focus
		{
			outline: none;
		}
		.TableMain
		{
			padding-top: 15px;
			width: 100%;
		}
		.TableMainPopup
		{
			@include TableMain;
		}
		.TableMainWithShadow
		{
			@include TableMain;
			box-shadow: 0px 0px 3px 0px rgba(0,0,0,0.2);
			margin-top: 15px;
			padding: 15px;
			background-color: $colors.DataBackgroundColor;
			border-radius: $radius.l;
		}
		.TableMainTransaction
		{
			padding-top: 5px;
		}
		.TableMainTransactionPopUp
		{
			padding-bottom: 10px;
			padding-left: 5px;
			padding-top: 0px;
		}
		.TableMainWhiteHeader
		{
			background-color: transparent;
		}
		.TableMainWhiteHeader > .row:first-child
		{
			background-color: $colors.DataBackgroundColor;
			border-bottom: $borders.xs solid rgba(0, 0, 0, 0.1);
			padding-bottom: 10px;
		}
		.TableMainPopover
		{
			padding: 10px;
		}
	#endregion
	#region Form
		FORM
		{
			height: 100%;
		}
		.Form INPUT::-ms-clear
		{
			display: none;
		}
		.Popup
		{
		}
		.Form
		{
			gx-form-popup-class: Popup;
			margin: 0pt;
			padding: 0pt;
			background-color: $colors.BackgroundColor;
			background-image: none;
			font-family: $fonts.primary-regular;
			color: $colors.gray08;
			height: 100%;
		}
		.FormNoBackgroundColor
		{
			@include Form;
			background-color: $colors.DataBackgroundColor !important;
		}
		.FormBackgroundImage
		{
			@include Form;
			overflow: auto;
			background-image: gx-image(LoginImageDark);
			background-size: cover;
		}
		.FormSplitScreen
		{
			@include Form;
			background-color: $colors.DataBackgroundColor;
		}
	#endregion
	#region Attribute
		.Label
		{
			@include TextBlock;
			white-space: normal;
			color: $colors.gray08;
			font-size: $fontSizes.s;
			font-weight: bold;
		}
		.dp_container
		{
			position: relative;
		}
		.DataContentCell
		{
			padding-bottom: 2px;
			padding-left: 10px;
			padding-right: 20px;
			padding-top: 2px;
			white-space: nowrap;
			vertical-align: middle;
		}
		.RequiredDataContentCell
		{
			@include DataContentCell;
		}
		.DataDescriptionCell
		{
			padding-bottom: 10px;
			padding-left: 15px;
			padding-right: 10px;
			padding-top: 10px;
		}
		.DataDescription
		{
			white-space: normal;
			font-size: $fontSizes.s;
			font-weight: normal;
			display: block;
			padding-left: 5px;
			color: $colors.gray07;
		}
		.Attribute
		{
			gx-label-class: Label;
			margin-left: 5px;
			display: inline-block;
			background-color: transparent;
			border: $borders.xs solid $colors.gray05;
			font-size: $fontSizes.s;
			font-style: normal;
			font-variant: normal;
			text-decoration: none;
			color: $colors.gray08;
			max-width: 206px;
			text-indent: 0px;
			padding-bottom: 0px;
			padding-left: 8px;
			padding-right: 8px;
			padding-top: 0px;
			height: 29px;
		}
		.ReadonlyAttribute
		{
			@include Attribute;
		}
		.BlobContentAttribute
		{
			@include Attribute;
			height: 400px;
			width: 100%;
			max-width: 100%;
		}
		.AttributeRealWidthTotalizer
		{
			@include Attribute;
			font-weight: bold;
			border-width: 0px;
		}
		.AttributeAcceptDrag
		{
			@include Attribute;
		}
		.AttributeTotalizer
		{
			@include Attribute;
			padding-left: 1px;
			padding-right: 1px;
			white-space: normal;
			border-width: 0px;
			font-weight: bold;
			line-height: 37px;
			margin-right: 5px;
		}
		.AttributeDateTime
		{
			@include Attribute;
		}
		.AttributeRealWidthDateTime
		{
			@include AttributeDateTime;
		}
		span.AttributeDateTime
		{
			@include AttributeDateTime;
			margin-left: 5px;
			margin-right: 5px;
			padding: 1px;
			display: inline-block;
			border-style: none;
			font-size: $fontSizes.s;
			font-style: normal;
			font-variant: normal;
			max-height: 30px;
			width: auto;
			max-width: 100%;
			text-indent: 0px;
			margin-bottom:  0px !important;
		}
		.AttributeCheckBox
		{
			@include Attribute;
			border-style: none;
			max-width: 100%;
		}
		.AttributeRealWidthCheckBox
		{
			@include Attribute;
			border-style: none;
			max-width: 100%;
			padding-left: 20px;
			padding-top: 5px;
		}
		.input-group>.ErrorAttributeRealWidth
		{
			margin-bottom: 20px;
		}
		.input-group>.ErrorAttributeRealWidth  .input-group-btn A.btn
		{
			margin-top: -20px;
		}
		.AttributeCheckBox.gx-checkbox-wrapper
		{
			display:flex;
		}
		span.ReadonlyAttribute.gx-checkbox-wrapper
		{
			min-height: 27px;
			display: inline-block;
			padding-top: 7px;
			padding-left: 20px;
		}
		span.ReadonlyAttributeCheckBox.gx-checkbox-wrapper
		{
			padding-left: 25px;
		}
		.ReadonlyAttributeCheckBox label,.AttributeCheckBox label
		{
			margin-bottom: 0;
			padding-top: 1px;
			white-space: normal;
		}
		.AttributeCheckBoxLabel  .gx-attribute
		{
			height:34px;
		}
		.ActionAttribute
		{
			margin-left: 0px;
			padding: 6px;
			background-color: $colors.gray04;
			border-width: 0px;
			border-radius: 25px;
			vertical-align: middle;
		}
		.ActionBaseColorAttribute
		{
			@include ActionAttribute;
		}
		.ErrorAttribute
		{
			@include Attribute;
			border-color: $colors.Danger;
		}
		.WarningAttribute
		{
			@include Attribute;
			border: $colors.Warning;
			border-style: solid;
		}
		span.Attribute,span.ReadonlyAttribute,span.AttributeRealWidth,span.ReadonlyAttributeRealWidth
		{
			@include Attribute;
			margin-right: 5px;
			padding-bottom: 1px;
			padding-left: 1px;
			padding-right: 1px;
			padding-top: 7px;
			white-space: normal;
			border-style: none;
			max-height: 30px;
			width: auto;
			max-width: 100%;
			margin-right: 5px;
			padding-bottom: 1px;
			padding-left: 1px;
			padding-right: 1px;
			padding-top: 7px;
			margin-bottom: 0px !important;
		}
		span.AttributeRealWidthDateTime
		{
			@include AttributeRealWidthDateTime;
			margin-bottom:  0px !important;
		}
		.AttributeTitleWWP
		{
			margin-left: 0px;
			color: $colors.gray08;
			margin-bottom:  0px !important;
			font-size: $fontSizes.l;
			font-weight: normal;
		}
		.AttributeManageFilters
		{
			@include Attribute;
			padding-left: 12px;
			padding-right: 12px;
			border-radius: $radius.m;
			height: 32px;
		}
		.AttributeManageFilters:focus
		{
			border-color: $colors.BaseColor;
			outline: 0;
		}
		.AttributeDate
		{
			@include Attribute;
			min-width: 80px;
		}
		span.AttributeDate
		{
			@include AttributeDate;
			padding-top: 7px;
			border-width: 0px;
		}
		.AttributeRealWidthDate
		{
			@include AttributeDate;
		}
		.AttributeInactive
		{
			@include Attribute;
			color: $colors.gray07;
		}
		.AttributeRealWidth, .ReadonlyAttributeRealWidth
		{
			@include Attribute;
			width: auto;
			max-width: 100%;
		}
		.AttributeRegister
		{
			@include Attribute;
			margin-right: 5px;
		}
		.DataContentCell span.Attribute, .DataContentCellView span.Attribute, .RequiredDataContentCell span.Attribute, .DataContentCell span.AttributeRealWidth, .DataContentCellView span.AttributeRealWidth, .RequiredDataContentCell span.AttributeRealWidth
		{
			color: $colors.gray07;
		}
		/* GeneXus Issue in TextAreas (assigns ReadonlyAttribute)*/
		.DataContentCell span.ReadonlyAttribute, .DataContentCellView span.ReadonlyAttribute, .RequiredDataContentCell span.ReadonlyAttribute, .DataContentCell span.ReadonlyAttributeRealWidth, .DataContentCellView span.ReadonlyAttributeRealWidth, .RequiredDataContentCell span.ReadonlyAttributeRealWidth
		{
			color: $colors.gray07;
		}
		.DataContentCell span.AttributeDateTime, .DataContentCellView span.AttributeDateTime, .RequiredDataContentCell span.AttributeDateTime, .DataContentCell span.AttributeDateTimeRealWidth, .DataContentCellView span.AttributeDateTimeRealWidth, .RequiredDataContentCell span.AttributeDateTimeRealWidth
		{
			color: $colors.gray07;
		}
		.DataContentCell span.AttributeDate, .DataContentCellView span.AttributeDate, .RequiredDataContentCell span.AttributeDate, .DataContentCell span.AttributeDateRealWidth, .DataContentCellView span.AttributeDateRealWidth, .RequiredDataContentCell span.AttributeDateRealWidth
		{
			color: $colors.gray07;
		}
		TEXTAREA.Attribute
		{
			border: $borders.xs solid $colors.gray05;
			border-radius: $radius.m;
			width: auto;
			max-width: 100%;
			margin-bottom: -5px;
		}
		TEXTAREA.Attribute:focus
		{
			border: $borders.xs solid $colors.BaseColor;
			padding-bottom: 6px;
			box-shadow: 0px 0px 2px $colors.ActionBorder_and_FocusColor;
		}
		object[data='about: blank']
		{
			display: none !important;
		}
		.AttributeCheckBox  label
		{
			margin-bottom: 0px;
		}
		.AttributeImportFileCell .gx-label  div object
		{
			display: none !important;
		}
		.input-group > .AttributeDateTime  .input-group-btn>A.btn
		{
			margin-left: -32px;
		}
		.input-group > input
		{
			border-radius: 4px !important;
			padding-right: 46px;
		}
		.form-control option, .Attribute option
		{
			background-color: $colors.DataBackgroundColor;
		}
		.gx-attribute img.Attribute,.gx-attribute img.ReadonlyAttribute
		{
			max-height: 350px;
		}
		.field.Attribute
		{
			max-width: inherit;
		}
		.input-group-btn:nth-child(2) > .btn, .input-group-btn:nth-child(2) > .btn-group
		{
			transition: border-color ease-in-out .15s,box-shadow ease-in-out .15s;
			margin-left: 4px;
		}
		.form-control-static
		{
			padding-bottom: 0px;
			padding-top: 0px;
			min-height: 0px;
		}
		.Attribute .form-control-static,.AttributeRealWidth .form-control-static
		{
			min-height: 28px;
		}
		.form-control:focus
		{
			border-color: $colors.BaseColor;
			box-shadow: 0px 0px 2px $colors.ActionBorder_and_FocusColor;
		}
		.checkbox LABEL SPAN
		{
			border-style: none;
		}
		.checkbox LABEL SPAN  INPUT
		{
			margin-top: 2px;
			height: 14px;
			width: 14px;
		}
		DIV.checkbox
		{
			border-style: none;
		}
		.input-group-btn
		{
			width: auto;
		}
		.input-group
		{
			border-collapse: collapse;
		}
		.dp_container .input-group .input-group-btn>A.btn
		{
			padding-left: 6px;
			padding-right: 3px;
			padding-top: 2px;
			z-index:2;
			height: 23px;
			margin-left: -29px;
		}
		.input-group  A.btn IMG
		{
			height: 17px;
		}
		.input-group .input-group-btn > A.btn
		{
			border-style: none;
			margin-left: -27px;
			padding-bottom: 0px;
			padding-left: 6px;
			padding-right: 6px;
			padding-top: 0px;
			z-index: 3;
			line-height: 17px;
			box-shadow: none;
		}
		.input-group  A.btn-default:focus
		{
			background-color: $colors.DataBackgroundColor;
			border-bottom-color: $colors.gray05;
		}
		.input-group  A.btn-default:hover
		{
			background-color: $colors.DataBackgroundColor;
			border-color: $colors.gray05;
			padding-left: 6px;
			z-index: 6;
		}
		.input-group .form-control:focus + span.input-group-btn > A.btn
		{
			box-shadow: none;
		}
		.input-group .ErrorAttributeDate + span.input-group-btn > A.btn, .input-group .ErrorAttribute + span.input-group-btn > A.btn
		{
			border-color: $colors.Danger;
		}
		.form-horizontal .checkbox
		{
			padding-top: 0px;
		}
		span.Attribute  A:visited, span.ReadonlyAttribute  A:visited
		{
			color: $colors.BaseColorForecolor;
		}
		.gx-pwd-reveal-btn > .btn.btn-default
		{
			margin-left: -39px;
			border-style: none;
			z-index: 3;
		}
		.gx-pwd-reveal-btn > .btn.btn-default:hover,.gx-pwd-reveal-btn > .btn.btn-default:focus
		{
			background-color: transparent;
			outline: none;
			box-shadow: none;
		}
		.AttributeImage30
		{
			border-style: none;
			max-height: 30px;
			max-width: 30px;
			object-fit: contain;
		}
		.ImageAttribute
		{
			@include Attribute;
		}
		.RequiredDataContentCellFL .AttributeFLLabel:after, .RequiredDataContentCell .AttributeLabel:after, .RequiredDataContentCell .AttributeDateLabel:after,.RequiredDataContentCell .AttributeDateTimeLabel:after, .RequiredDataContentCellFL .Label:after, .RequiredDataContentCell .Label:after, .RequiredDataContentCell .AttributeCheckBoxLabel:after, .RequiredDataContentCell .AttributeRealWidthLabel:after, .RequiredDataContentCell .AttributeRealWidthDateLabel:after, .RequiredDataContentCell .AttributeRealWidthDateTimeLabel:after, .RequiredDataContentCell .AttributeRealWidthCheckBoxLabel:after
		{
			margin-left: 5px;
			color: $colors.gray08;
			content: "*";
			line-height: 0;
		}
		.Attribute>.gx-radio-label
		{
			background-color: $colors.DataBackgroundColor;
			color: $colors.gray08;
			border-color: $colors.gray05;
			outline: 0;
		}
		.Attribute>.gx-radio-label.active
		{
			background-color:$colors.gray05;
			box-shadow:none;
			outline: 0;
			border-color: $colors.gray05;
			color: $colors.gray08;
		}
		.WorkWith TR:not(.WCD_tr) span.Attribute.gx-radio-button
		{
			display:flex;
		}
		.WorkWith TR:not(.WCD_tr) span.Attribute.gx-radio-button > label
		{
			vertical-align: top;
			box-shadow: none;
			padding-top: 3px;
		}
		.Attribute.gx-radio-button
		{
			padding-top:0;
			margin-left: 4px;
