	#region Buttons
		.Button
		{
			padding-left: 12px;
			padding-right: 12px;
			white-space: nowrap;
			background-color: $colors.BaseColor;
			display: inline-block;
			text-decoration: none;
			color: $colors.BaseForecolor;
			border: $borders.xs solid $colors.ActionBorder_and_FocusColor;
			text-align: center;
			text-indent: 0pt;
			vertical-align: middle;
			cursor: pointer;
			font-size: $fontSizes.s;
			font-style: normal;
			font-variant: normal;
			margin-right: 3pt;
			box-shadow: 0px 7px 10px -5px	$colors.BaseColorShadow;
			padding-bottom: 7px;
			padding-top: 7px;
			border-style: none;
			font-weight: 400;
			min-width: 0px;
			transition: color .15s ease-in-out,background-color .15s ease-in-out,border-color .15s ease-in-out,box-shadow .15s ease-in-out;
			border-radius: $radius.m;
		}
		.Button:hover
		{
			background-color: $colors.BaseColor;
			box-shadow: 0px 14px 26px -12px $colors.BaseColorShadow;
			color: white;
		}
		.BtnDefault
		{
			@include Button;
			padding-bottom: 7px;
			padding-top: 7px;
			background-color: $colors.gray07;
			border-style: none;
			font-weight: 400;
			color: white;
			min-width: 0px;
			line-height: 21px;
			transition: color .15s ease-in-out,background-color .15s ease-in-out,border-color .15s ease-in-out,box-shadow .15s ease-in-out;
			box-shadow: none;
		}
		.BtnDefaultMarginRight0
