	#region PagingButtons_WithoutPaginationBar
		.PagingButtons
		{
			@include Image;
			background-repeat: no-repeat;
			height: 21px;
			width: 21px;
			cursor: pointer;
		}
		.PagingButtonsFirst
		{
			@include PagingButtons;
			background-image: gx-image(PageFirst);
		}
		.PagingButtonsLast
		{
			@include PagingButtons;
			background-image: gx-image(PageLast);
		}
		.PagingButtonsNext
		{
			@include PagingButtons;
			background-image: gx-image(PageNext);
		}
		.PagingButtonsPrevious
		{
			@include PagingButtons;
			background-image: gx-image(PagePrevious);
		}
	#endregion
	#region GridTitleSortable_WithoutTitleFilter
		.GridTitleSortedAsc
		{
			background-image: gx-image(DDOSortedASC);
			background-position: 100% 60%;
			background-repeat: no-repeat;
			padding-right: 12px;
			cursor: pointer;
		}
		.GridTitleSortedAsc  A
		{
			text-decoration: none;
			color: black;
		}
		.GridTitleSortedAsc  A:hover
		{
			text-decoration: none;
		}
		.GridTitleSortedDsc
		{
			background-image: gx-image(DDOSortedDSC);
			background-position: 100% 60%;
			background-repeat: no-repeat;
			padding-right: 12px;
			cursor: pointer;
		}
		.GridTitleSortedDsc  A
		{
			text-decoration: none;
			color: black;
		}
		.GridTitleSortedDsc  A:hover
		{
			text-decoration: none;
		}
		.GridTitleSortable
		{
			cursor: pointer;
		}
		.GridTitleSortable  A
		{
			text-decoration: none;
			color: black;
		}
		.GridTitleSortable  A:hover
		{
			text-decoration: none;
		}
		.GridTitleSortedAscCS A
		{
			background-image: gx-image(DDOSortedASC);
			background-position: 100% 60%;
			background-repeat: no-repeat;
			padding-right: 18px;
			cursor: pointer;
		}
		.GridTitleSortedDscCS A
		{
			background-image: gx-image(DDOSortedDSC);
			background-position: 100% 60%;
			background-repeat: no-repeat;
			padding-right: 18px;
			cursor: pointer;
		}
		.GridTitleSortableCS A
		{
			cursor: pointer;
		}
	#endregion
	#region PaginationBar
		.PaginationBar
		{
			border-top: $borders.xs solid $colors.gray05;
			background-color: $colors.gray02;
			box-shadow: 0px 1px 3px rgba(0,0,0,0.2);
		}
		.PaginationBarCaption.PaginationBarFiltered
		{
			padding-top: 2px;
			line-height: 39px;
		}
		.PaginationBarFiltersCaption
		{
			display: block;
			font-size: $fontSizes.s;
			color: $colors.gray07;
		}
		.PaginationBar  .pagination>li>a:focus, .PaginationBar .pagination>li>a:hover, .PaginationBar .pagination>li>span:focus, .PaginationBar .pagination>li>span:hover
		{
			background-color: $colors.gray03;
			border-color: $colors.gray05;
			color: $colors.BaseColorForecolor;
		}
		.PaginationBar  UL
		{
			border-radius: 0px;
			margin-bottom: 1px;
			margin-left: 4px;
			margin-right: 4px;
			margin-top: 5px;
		}
		.PaginationBar  UL .disabled  A
		{
			background-color: $colors.gray02;
			border-color: $colors.gray05;
		}
		.PaginationBar  UL .disabled  A:hover
		{
			background-color: $colors.gray02;
			border-color: $colors.gray05;
		}
		.PaginationBar  UL .active A
		{
			background-color: $colors.BaseColor;
			border-color: $colors.BaseColor;
			z-index: 1;
			color: white;
		}
		.PaginationBar  UL LI A
		{
			background-color: $colors.DataBackgroundColor;
			border-color: $colors.gray05;
			color: $colors.BaseColorForecolor;
		}
		.PaginationBar  UL .active A:focus
		{
			background-color: $colors.BaseColor;
			border-color: $colors.BaseColor;
			z-index: 0;
			color: white;
		}
		.PaginationBar  UL .active A:hover
		{
			background-color: $colors.BaseColor;
			border-color: $colors.BaseColor;
			color: white;
		}
		.PaginationBar  .PaginationBarCaption
		{
			padding-left: 10px;
			padding-right: 20px;
			font-size: $fontSizes.s;
			color: $colors.gray07;
			line-height: 41px;
		}
		.PaginationBarEmptyGrid  .PaginationBarCaption
		{
			padding-bottom: 30px;
			padding-left: 20px;
			padding-right: 20px;
			padding-top: 30px;
			font-size: $fontSizes.m;
			color: $colors.GridForecolor;
		}
		.PaginationWithLinksCell .PaginationBar
		{
			background-color: Transparent;
		}
		.PaginationWithLinksCell .PaginationBar UL LI A
		{
			background-color: Transparent;
			border-style: none;
		}
		.PaginationWithLinksCell .PaginationBar UL .disabled A
		{
			background-color: Transparent;
			color: $colors.gray07;
			text-decoration: none;
		}
		.PaginationWithLinksCell .PaginationBar UL .active A
		{
			color: $colors.BaseColor;
			font-weight: bold;
		}
		.PaginationWithLinksCell .PaginationBar UL A:hover
		{
			background-color : transparent;
			text-decoration: underline;
		}
		.rowsperpage  BUTTON
		{
			background-color: transparent;
			border-color: transparent;
			color: $colors.gray07;
		}
		.rowsperpage  BUTTON:hover
		{
			background-color: transparent;
			border-color: $colors.gray05;
			border-style: solid;
			color: $colors.gray07;
		}
		.rowsperpage  .caret
		{
			display: none;
		}
		.rowsperpage  .dropdown-menu A
		{
			color: $colors.gray07;
		}
		.rowsperpage  .dropdown-menu A  SPAN
		{
			padding-left: 20px;
			padding-right: 10px;
			font-family: $fonts.primary-regular;
			font-size: $fontSizes.s;
			color: $colors.gray08;
		}
		.rowsperpage  .selected SPAN
		{
			font-weight: bold;
		}
		.rowsperpage  LI.caption
		{
			line-height: 20px;
		}
		.rowsperpage  LI.selected
		{
			background-color: $colors.gray01;
		}
		.rowsperpage  .dropdown-menu
		{
			background-color: $colors.DataBackgroundColor;
			min-width: 0px;
		}
		.rowsperpage  .btn-primary:focus
		{
			background-color: transparent;
			border-color: transparent;
			color: $colors.gray07;
		}
		.rowsperpage button:hover .caret, .rowsperpage.open .caret
		{
			margin-left: 7px;
			display: inherit;
		}
		.rowsperpage.open > .dropdown-toggle.btn-primary
		{
			background-color: transparent;
			border-color: $colors.gray05;
			color: $colors.gray07;
		}
		@media (max-width: 767px) /*ExtraSmall*/
		{
			.PaginationBarCaption.PaginationBarFiltered
			{
				display: none;
			}
		}
	#endregion
	#region ConditionalFormattingAndTags
		th.WWColumn,th.WWIconActionColumn,th.WWActionColumn
		{
			box-shadow: none;
		}
		.ConditionalFormattingSelected span
		{
			font-weight: bold;
		}
		.ConditionalFormattingFilterIcon
		{
			min-width: 25px;
			text-align: center;
		}
		.TagColumn>p
		{
			text-align: center;
		}
		.TagColumn
		{
			padding-right: 5px;
			width: 30px;
		}
		.TagColumn span.Attribute,.TagColumn span.ReadonlyAttribute
		{
			margin-left: 0px;
			margin-right: 0px;
		}
		.TagAfterText
		{
			margin-left: 5px;
			margin-right: 0px;
		}
		.TagBeforeText
		{
			margin-right: 5px;
		}
		.AttributeTag
		{
			@include Attribute;
			padding-bottom: 3px;
			padding-left: 6px;
			padding-right: 6px;
			padding-top: 3px;
			white-space: nowrap;
			border-style: none;
			border-radius: .25em;
			font-size: $fontSizes.xs;
			color: white;
			height: auto;
			line-height: 13px;
			background-color: $colors.BaseColor;
		}
		.AttributeTagSuccess
		{
			@include AttributeTag;
			background-color: $colors.Success_CondForm;
		}
		.AttributeTagWarning
		{
			@include AttributeTag;
			background-color: $colors.Warning;
		}
		.AttributeTagDanger
		{
			@include AttributeTag;
			background-color: $colors.Danger_CondForm;
		}
		.AttributeTagInfoLight
		{
			@include AttributeTag;
			background-color: $colors.InfoLight;
		}
		.AttributeTagInfo
		{
			@include AttributeTag;
			background-color: $colors.Info_CondForm;
		}
		.TableMerged .TagAfterText,.TableMerged .TagBeforeText
		{
			margin-top: 7px;
		}
		.TableMerged i.TagAfterText,.TableMerged i.TagBeforeText
		{
			vertical-align: middle;
			margin-top: 4px;
		}
		.DscTop .TableMerged .TagAfterText,.DscTop .TableMerged .TagBeforeText
		{
			vertical-align:top;
			margin-top: 0;
		}
		.DscTop .TableMerged i.TagAfterText, .DscTop .TableMerged i.TagBeforeText
		{
			margin-top: 2px;
		}
