		{
			font-size: $fontSizes.font-icon-s;
			color: $colors.BaseColor;
		}
		.FontColorIconDanger
		{
			@include FontColorIcon;
			color: $colors.Danger_CondForm;
		}
		.FontColorIconWarning
		{
			@include FontColorIcon;
			color: $colors.Warning;
		}
		.FontColorIconSuccess
		{
			@include FontColorIcon;
			color: $colors.Success_CondForm;
		}
		.FontColorIconInfo
		{
			@include FontColorIcon;
			color: $colors.Info_CondForm;
		}
		.FontColorIconInfoLight
		{
			@include FontColorIcon;
			color: $colors.InfoLight;
		}
		.FontColorIconSmall
		{
			padding-bottom: 3px;
			padding-top: 3px;
			font-size: $fontSizes.font-icon-xs  !important;
		}
		.WWColumnSuccess
