	#region GXMask
		DIV.gx-mask
		{
			background-color: black;
			left: 0px;
			position: absolute;
			top: 0px;
			height: 100%;
			width: 100%;
			animation:  entermask 1s;
			-webkit-animation:  entermask 1s;
			-ms-filter: "alpha(opacity=10)";
			opacity: .10;
		}
		Body > DIV.gx-mask
		{
			background-color: black;
			left: 0px;
			position: absolute;
			top: 0px;
			z-index: 1030;
			height: 100%;
			width: 100%;
			animation:  entermask 1s;
			-webkit-animation:  entermask 1s;
			-ms-filter: "alpha(opacity=10)";
			opacity: .10;
		}
		DIV.gx-unmask
		{
			background-color: transparent;
			animation:  leavemask .3s;
			-webkit-animation:  leavemask .3s;
		}
		BODY.gx-masked DIV.gx-mask
		{
			bottom: 0px;
			position: fixed;
		}
		.gx-masked-relative
		{
			position: relative;
		}
		.gx-grid > .gx-mask
		{
			z-index:999;
			max-width:100%;
		}
		.gx-grid > table.gx-masked-relative
		{
			position: initial;
		}
		.mask
		{
			background-color: #000;
			bottom: 0px;
			left: 0px;
			position: absolute;
			right: 0px;
			top: 0px;
			z-index: 1;
			display: none;
			opacity: .25;
			filter: alpha(opacity=25);
		}
		.mask.block-scrollbars
		{
			overflow: auto;
		}
		.masked select, .drag select, .hide-select select
		{
			_visibility: hidden;
		}
